class Solution {
    public int shortestMatchingSubstring(String s, String p) {
        int n = s.length();
        int m = p.length();
        int[][] dp = new int[n + 1][m + 1];
        for (int i = 0; i <= n; i++) {
            dp[i][0] = 0;
        }
        for (int j = 0; j <= m; j++) {
            dp[0][j] = 0;
        }
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                if (p.charAt(j - 1) == '*') {
                    dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
                } else if (p.charAt(j - 1) == s.charAt(i - 1)) {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                } else {
                    dp[i][j] = 0;
                }
            }
        }
        int maxLength = 0;
        for (int j = 0; j <= m; j++) {
            maxLength = Math.max(maxLength, dp[n][j]);
        }
        return maxLength;
    }
}
